export const ListScenesResponseJSON = {
  /**
   * Serializes ListScenesResponse to JSON.
   */
  encode: function (msg: PartialDeep<ListScenesResponse>): string {
    return JSON.stringify(ListScenesResponseJSON._writeMessage(msg));
  },

  /**
   * Deserializes ListScenesResponse from JSON.
   */
  decode: function (json: string): ListScenesResponse {
    return ListScenesResponseJSON._readMessage(
      ListScenesResponseJSON.initialize(),
      JSON.parse(json),
    );
  },

  /**
   * Initializes ListScenesResponse with all fields set to their default value.
   */
  initialize: function (msg?: Partial<ListScenesResponse>): ListScenesResponse {
    return {
      status: common.ResponseStatusJSON.initialize(),
      scenes: [],
      totalCount: 0,
      page: 0,
      pageSize: 0,
      ...msg,
    };
  },

  /**
   * @private
   */
  _writeMessage: function (
    msg: PartialDeep<ListScenesResponse>,
  ): Record<string, unknown> {
    const json: Record<string, unknown> = {};
    if (msg.status) {
      const _status_ = common.ResponseStatusJSON._writeMessage(msg.status);
      if (Object.keys(_status_).length > 0) {
        json["status"] = _status_;
      }
    }
    if (msg.scenes?.length) {
      json["scenes"] = msg.scenes.map(SceneJSON._writeMessage);
    }
    if (msg.totalCount) {
      json["totalCount"] = msg.totalCount;
    }
    if (msg.page) {
      json["page"] = msg.page;
    }
    if (msg.pageSize) {
      json["pageSize"] = msg.pageSize;
    }
    return json;
  },

  /**
   * @private
   */
  _readMessage: function (
    msg: ListScenesResponse,
    json: any,
  ): ListScenesResponse {
    const _status_ = json["status"];
    if (_status_) {
      common.ResponseStatusJSON._readMessage(msg.status, _status_);
    }
    const _scenes_ = json["scenes"];
    if (_scenes_) {
      for (const item of _scenes_) {
        const m = SceneJSON.initialize();
        SceneJSON._readMessage(m, item);
        msg.scenes.push(m);
      }
    }
    const _totalCount_ = json["totalCount"] ?? json["total_count"];
    if (_totalCount_) {
      msg.totalCount = protoscript.parseNumber(_totalCount_);
    }
    const _page_ = json["page"];
    if (_page_) {
      msg.page = protoscript.parseNumber(_page_);
    }
    const _pageSize_ = json["pageSize"] ?? json["page_size"];
    if (_pageSize_) {
      msg.pageSize = protoscript.parseNumber(_pageSize_);
    }
    return msg;
  },
};
